import json
import xml.etree.ElementTree as ET

def convert_json_to_dict(json_string):
    """
    Convert a JSON string to a Python dictionary.

    Args:
        json_string (str): A JSON formatted string

    Returns:
        dict: The corresponding Python dictionary

    Raises:
        ValueError: If the input is not valid JSON
    """
    try:
        return json.loads(json_string)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON: {e}")

def convert_to_dict(data_string, format_type):
    """
    Convert a data string to a dictionary or structured object based on format type.

    Args:
        data_string (str): A data string in JSON or XML format
        format_type (str): The format type ('json' or 'xml')

    Returns:
        dict or ElementTree: Dictionary for JSON, ElementTree object for XML

    Raises:
        ValueError: If the format is not supported or data is invalid
    """
    if format_type.lower() == 'json':
        try:
            return json.loads(data_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON: {e}")
    elif format_type.lower() == 'xml':
        try:
            return ET.fromstring(data_string)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML: {e}")
    else:
        raise ValueError(f"Unsupported format type: {format_type}. Supported formats are 'json' and 'xml'")

turn3_code:
import json
import configparser
import io

valid_formats = ["json", "ini"]

def convert_serialized_data(raw_bytes, format_hint):
    """
    Convert serialized data to a Python object based on format hint.

    Args:
        raw_bytes (bytes): The serialized data in bytes
        format_hint (str): The format type ('json', 'ini', 'pickle')

    Returns:
        object: The deserialized Python object

    Raises:
        ValueError: If the format is not supported or data is invalid
    """
    if format_hint not in valid_formats:
        raise ValueError(f"Unsupported format: {format_hint}. Supported formats are: {', '.join(valid_formats)}")

    if format_hint == 'json':
        try:
            return json.loads(raw_bytes.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            raise ValueError(f"Invalid JSON data: {e}")
    elif format_hint == 'ini':
        try:
            config = configparser.ConfigParser()
            config.read_string(raw_bytes.decode('utf-8'))
            # Convert ConfigParser to dictionary
            result = {}
            for section in config.sections():
                result[section] = dict(config.items(section))
            return result
        except (configparser.Error, UnicodeDecodeError) as e:
            raise ValueError(f"Invalid INI data: {e}")

